   109→func runTrailListAll(w io.Writer, statusFilter string, jsonOutput bool) error {
   110→	// Fetch remote trails branch so we see trails from collaborators
   111→	fetchTrailsBranch()
   112→
   113→	repo, err := strategy.OpenRepository(context.Background())
   114→	if err != nil {
   115→		return fmt.Errorf("failed to open repository: %w", err)
   116→	}
   117→
   118→	store := trail.NewStore(repo)
   119→	trails, err := store.List()
   120→	if err != nil {
   121→		return fmt.Errorf("failed to list trails: %w", err)
   122→	}
   123→
   124→	if trails == nil {
   125→		trails = []*trail.Metadata{}
   126→	}
   127→
   128→	// Apply status filter
   129→	if statusFilter != "" {
   130→		status := trail.Status(statusFilter)
   131→		if !status.IsValid() {
   132→			return fmt.Errorf("invalid status %q: valid values are %s", statusFilter, formatValidStatuses())
   133→		}
   134→		var filtered []*trail.Metadata
   135→		for _, t := range trails {
   136→			if t.Status == status {
   137→				filtered = append(filtered, t)
   138→			}
   139→		}
   140→		trails = filtered
   141→	}
   142→
   143→	// Sort by updated_at descending
   144→	sort.Slice(trails, func(i, j int) bool {
   145→		return trails[i].UpdatedAt.After(trails[j].UpdatedAt)
   146→	})
   147→
   148→	if jsonOutput {
   149→		enc := json.NewEncoder(w)
   150→		enc.SetIndent("", "  ")
   151→		if err := enc.Encode(trails); err != nil {
   152→			return fmt.Errorf("failed to encode JSON: %w", err)
   153→		}
   154→		return nil
   155→	}
   156→
   157→	if len(trails) == 0 {
   158→		fmt.Fprintln(w, "No trails found.")
   159→		fmt.Fprintln(w)
   160→		fmt.Fprintln(w, "Commands:")
   161→		fmt.Fprintln(w, "  entire trail create   Create a trail for the current branch")
   162→		fmt.Fprintln(w, "  entire trail list     List all trails")
   163→		fmt.Fprintln(w, "  entire trail update   Update trail metadata")
   164→		return nil
   165→	}
   166→
   167→	// Table output
   168→	fmt.Fprintf(w, "%-30s %-40s %-13s %-15s %s\n", "BRANCH", "TITLE", "STATUS", "AUTHOR", "UPDATED")
   169→	for _, t := range trails {
   170→		branch := stringutil.TruncateRunes(t.Branch, 30, "...")
   171→		title := stringutil.TruncateRunes(t.Title, 40, "...")
   172→		fmt.Fprintf(w, "%-30s %-40s %-13s %-15s %s\n",
   173→			branch, title, t.Status, stringutil.TruncateRunes(t.Author, 15, "..."), timeAgo(t.UpdatedAt))
   174→	}
   175→
   176→	return nil
   177→}
