   201→//nolint:cyclop // sequential steps for creating a trail — splitting would obscure the flow
   202→func runTrailCreate(cmd *cobra.Command, title, body, base, branch, statusStr string, checkout bool) error {
   203→	w := cmd.OutOrStdout()
   204→	errW := cmd.ErrOrStderr()
   205→
   206→	repo, err := strategy.OpenRepository(context.Background())
   207→	if err != nil {
   208→		return fmt.Errorf("failed to open repository: %w", err)
   209→	}
   210→
   211→	// Determine base branch
   212→	if base == "" {
   213→		base = strategy.GetDefaultBranchName(repo)
   214→		if base == "" {
   215→			base = defaultBaseBranch
   216→		}
   217→	}
   218→
   219→	_, currentBranch, _ := IsOnDefaultBranch(context.Background()) //nolint:errcheck // best-effort detection
   220→	interactive := !cmd.Flags().Changed("title") && !cmd.Flags().Changed("branch")
   221→
   222→	if interactive {
   223→		// Interactive flow: title → body → branch (derived) → status
   224→		if err := runTrailCreateInteractive(&title, &body, &branch, &statusStr); err != nil {
   225→			return err
   226→		}
   227→	} else {
   228→		// Non-interactive: derive missing values from provided flags
   229→		if branch == "" {
   230→			if cmd.Flags().Changed("title") {
   231→				branch = slugifyTitle(title)
   232→			} else {
   233→				branch = currentBranch
   234→			}
   235→		}
   236→		if title == "" {
   237→			title = trail.HumanizeBranchName(branch)
   238→		}
   239→	}
   240→	if branch == "" {
   241→		return errors.New("branch name is required")
   242→	}
   243→
   244→	// Create the branch if it doesn't exist
   245→	needsCreation := branchNeedsCreation(repo, branch)
   246→	if needsCreation {
   247→		if err := createBranch(repo, branch); err != nil {
   248→			return fmt.Errorf("failed to create branch %q: %w", branch, err)
   249→		}
   250→		fmt.Fprintf(w, "Created branch %s\n", branch)
   251→	} else if currentBranch != branch {
   252→		fmt.Fprintf(errW, "Note: trail will be created for branch %q (not the current branch)\n", branch)
   253→	}
   254→
   255→	// Check if trail already exists for this branch
   256→	store := trail.NewStore(repo)
   257→	existing, err := store.FindByBranch(branch)
   258→	if err == nil && existing != nil {
   259→		fmt.Fprintf(w, "Trail already exists for branch %q (ID: %s)\n", branch, existing.TrailID)
   260→		return nil
   261→	}
   262→
   263→	// Determine status
   264→	var trailStatus trail.Status
   265→	if statusStr != "" {
   266→		trailStatus = trail.Status(statusStr)
   267→		if !trailStatus.IsValid() {
   268→			return fmt.Errorf("invalid status %q: valid values are %s", statusStr, formatValidStatuses())
   269→		}
   270→	} else {
   271→		trailStatus = trail.StatusDraft
   272→	}
   273→
   274→	// Generate trail ID
   275→	trailID, err := trail.GenerateID()
   276→	if err != nil {
   277→		return fmt.Errorf("failed to generate trail ID: %w", err)
   278→	}
   279→
   280→	// Get author (GitHub username, falls back to git user.name)
   281→	authorName := getTrailAuthor(repo)
   282→
   283→	now := time.Now()
   284→	metadata := &trail.Metadata{
   285→		TrailID:   trailID,
   286→		Branch:    branch,
   287→		Base:      base,
   288→		Title:     title,
   289→		Body:      body,
   290→		Status:    trailStatus,
   291→		Author:    authorName,
   292→		Assignees: []string{},
   293→		Labels:    []string{},
   294→		CreatedAt: now,
   295→		UpdatedAt: now,
   296→	}
   297→
   298→	if err := store.Write(metadata, nil, nil); err != nil {
   299→		return fmt.Errorf("failed to create trail: %w", err)
   300→	}
   301→
   302→	fmt.Fprintf(w, "Created trail %q for branch %s (ID: %s)\n", title, branch, trailID)
   303→
   304→	// Push the branch and trail data to origin
   305→	if needsCreation {
   306→		if err := pushBranchToOrigin(branch); err != nil {
   307→			fmt.Fprintf(errW, "Warning: failed to push branch: %v\n", err)
   308→		} else {
   309→			fmt.Fprintf(w, "Pushed branch %s to origin\n", branch)
   310→		}
   311→	}
   312→	if err := strategy.PushTrailsBranch(context.Background(), "origin"); err != nil {
   313→		fmt.Fprintf(errW, "Warning: failed to push trail data: %v\n", err)
   314→	}
   315→
   316→	// Checkout the branch if requested or prompted
   317→	if needsCreation && currentBranch != branch {
   318→		shouldCheckout := checkout
   319→		if !shouldCheckout && !cmd.Flags().Changed("checkout") {
   320→			// Interactive: ask whether to checkout
   321→			form := NewAccessibleForm(
   322→				huh.NewGroup(
   323→					huh.NewConfirm().
   324→						Title(fmt.Sprintf("Check out branch %s?", branch)).
   325→						Value(&shouldCheckout),
   326→				),
   327→			)
   328→			if formErr := form.Run(); formErr == nil && shouldCheckout {
   329→				checkout = true
   330→			}
   331→		}
   332→		if checkout {
   333→			if err := CheckoutBranch(context.Background(), branch); err != nil {
   334→				return fmt.Errorf("failed to checkout branch %q: %w", branch, err)
   335→			}
   336→			fmt.Fprintf(w, "Switched to branch %s\n", branch)
   337→		}
   338→	}
   339→
   340→	return nil
   341→}
