   365→func runTrailUpdate(w io.Writer, statusStr, title, body, branch string, labelAdd, labelRemove []string) error {
   366→	repo, err := strategy.OpenRepository(context.Background())
   367→	if err != nil {
   368→		return fmt.Errorf("failed to open repository: %w", err)
   369→	}
   370→
   371→	// Determine branch
   372→	if branch == "" {
   373→		branch, err = GetCurrentBranch(context.Background())
   374→		if err != nil {
   375→			return fmt.Errorf("failed to determine current branch: %w", err)
   376→		}
   377→	}
   378→
   379→	store := trail.NewStore(repo)
   380→	metadata, err := store.FindByBranch(branch)
   381→	if err != nil {
   382→		return fmt.Errorf("failed to find trail: %w", err)
   383→	}
   384→	if metadata == nil {
   385→		return fmt.Errorf("no trail found for branch %q", branch)
   386→	}
   387→
   388→	// Interactive mode when no flags are provided
   389→	noFlags := statusStr == "" && title == "" && body == "" && labelAdd == nil && labelRemove == nil
   390→	if noFlags {
   391→		// Build status options with current value as default.
   392→		// Exclude "done" and "closed" unless the trail is already in that status
   393→		// (otherwise the select would silently reset to the first option).
   394→		var statusOptions []huh.Option[string]
   395→		for _, s := range trail.ValidStatuses() {
   396→			if (s == trail.StatusDone || s == trail.StatusClosed) && s != metadata.Status {
   397→				continue
   398→			}
   399→			label := string(s)
   400→			if s == metadata.Status {
   401→				label += " (current)"
   402→			}
   403→			statusOptions = append(statusOptions, huh.NewOption(label, string(s)))
   404→		}
   405→		statusStr = string(metadata.Status)
   406→		title = metadata.Title
   407→		body = metadata.Body
   408→
   409→		form := NewAccessibleForm(
   410→			huh.NewGroup(
   411→				huh.NewSelect[string]().
   412→					Title("Status").
   413→					Options(statusOptions...).
   414→					Value(&statusStr),
   415→				huh.NewInput().
   416→					Title("Title").
   417→					Value(&title),
   418→				huh.NewText().
   419→					Title("Body").
   420→					Value(&body),
   421→			),
   422→		)
   423→		if formErr := form.Run(); formErr != nil {
   424→			return fmt.Errorf("form cancelled: %w", formErr)
   425→		}
   426→	}
   427→
   428→	// Validate status if provided
   429→	if statusStr != "" {
   430→		status := trail.Status(statusStr)
   431→		if !status.IsValid() {
   432→			return fmt.Errorf("invalid status %q: valid values are %s", statusStr, formatValidStatuses())
   433→		}
   434→	}
   435→
   436→	err = store.Update(metadata.TrailID, func(m *trail.Metadata) {
   437→		if statusStr != "" {
   438→			m.Status = trail.Status(statusStr)
   439→		}
   440→		if title != "" {
   441→			m.Title = title
   442→		}
   443→		if body != "" {
   444→			m.Body = body
   445→		}
   446→		for _, l := range labelAdd {
   447→			if !slices.Contains(m.Labels, l) {
   448→				m.Labels = append(m.Labels, l)
   449→			}
   450→		}
   451→		for _, l := range labelRemove {
   452→			m.Labels = slices.DeleteFunc(m.Labels, func(v string) bool { return v == l })
   453→		}
   454→	})
   455→	if err != nil {
   456→		return fmt.Errorf("failed to update trail: %w", err)
   457→	}
   458→
   459→	fmt.Fprintf(w, "Updated trail for branch %s\n", branch)
   460→	return nil
   461→}
