   466→func formatValidStatuses() string {
   467→	statuses := trail.ValidStatuses()
   468→	names := make([]string, len(statuses))
   469→	for i, s := range statuses {
   470→		names[i] = string(s)
   471→	}
   472→	return strings.Join(names, ", ")
   473→}
