   475→// runTrailCreateInteractive runs the interactive form for trail creation.
   476→// Prompts for title, body, branch (derived from title), and status.
   477→func runTrailCreateInteractive(title, body, branch, statusStr *string) error {
   478→	// Step 1: Title and body
   479→	form := NewAccessibleForm(
   480→		huh.NewGroup(
   481→			huh.NewInput().
   482→				Title("Trail title").
   483→				Placeholder("What are you working on?").
   484→				Value(title),
   485→			huh.NewText().
   486→				Title("Body (optional)").
   487→				Value(body),
   488→		),
   489→	)
   490→	if err := form.Run(); err != nil {
   491→		return fmt.Errorf("form cancelled: %w", err)
   492→	}
   493→	*title = strings.TrimSpace(*title)
   494→	if *title == "" {
   495→		return errors.New("trail title is required")
   496→	}
   497→
   498→	// Step 2: Branch (derived from title) and status
   499→	suggested := slugifyTitle(*title)
   500→	*branch = suggested
   501→
   502→	// Build status options, excluding done/closed
   503→	var statusOptions []huh.Option[string]
   504→	for _, s := range trail.ValidStatuses() {
   505→		if s == trail.StatusDone || s == trail.StatusClosed {
   506→			continue
   507→		}
   508→		statusOptions = append(statusOptions, huh.NewOption(string(s), string(s)))
   509→	}
   510→	if *statusStr == "" {
   511→		*statusStr = string(trail.StatusDraft)
   512→	}
   513→
   514→	form = NewAccessibleForm(
   515→		huh.NewGroup(
   516→			huh.NewInput().
   517→				Title("Branch name").
   518→				Placeholder(suggested).
   519→				Value(branch),
   520→			huh.NewSelect[string]().
   521→				Title("Status").
   522→				Options(statusOptions...).
   523→				Value(statusStr),
   524→		),
   525→	)
   526→	if err := form.Run(); err != nil {
   527→		return fmt.Errorf("form cancelled: %w", err)
   528→	}
   529→	*branch = strings.TrimSpace(*branch)
   530→	if *branch == "" {
   531→		*branch = suggested
   532→	}
   533→	return nil
   534→}
