   566→// slugifyTitle converts a title string into a branch-friendly slug.
   567→// Example: "Add user authentication" -> "add-user-authentication"
   568→func slugifyTitle(title string) string {
   569→	s := strings.ToLower(strings.TrimSpace(title))
   570→	// Replace spaces and underscores with hyphens
   571→	s = strings.NewReplacer(" ", "-", "_", "-").Replace(s)
   572→	// Remove anything that's not alphanumeric, hyphen, or slash
   573→	var b strings.Builder
   574→	prevHyphen := false
   575→	for _, r := range s {
   576→		if (r >= 'a' && r <= 'z') || (r >= '0' && r <= '9') || r == '/' {
   577→			b.WriteRune(r)
   578→			prevHyphen = false
   579→		} else if r == '-' && !prevHyphen {
   580→			b.WriteRune('-')
   581→			prevHyphen = true
   582→		}
   583→	}
   584→	return strings.Trim(b.String(), "-")
   585→}
