   158→// Read reads a trail by its ID from the entire/trails branch.
   159→func (s *Store) Read(trailID ID) (*Metadata, *Discussion, *Checkpoints, error) {
   160→	tree, err := s.getBranchTree()
   161→	if err != nil {
   162→		return nil, nil, nil, err
   163→	}
   164→
   165→	basePath := trailID.Path() + "/"
   166→
   167→	// Read metadata
   168→	metadataEntry, err := tree.FindEntry(basePath + metadataFile)
   169→	if err != nil {
   170→		return nil, nil, nil, fmt.Errorf("trail %s not found: %w", trailID, err)
   171→	}
   172→	metadataBlob, err := s.repo.BlobObject(metadataEntry.Hash)
   173→	if err != nil {
   174→		return nil, nil, nil, fmt.Errorf("failed to read metadata blob: %w", err)
   175→	}
   176→	metadataReader, err := metadataBlob.Reader()
   177→	if err != nil {
   178→		return nil, nil, nil, fmt.Errorf("failed to open metadata reader: %w", err)
   179→	}
   180→	defer metadataReader.Close()
   181→
   182→	var metadata Metadata
   183→	if err := json.NewDecoder(metadataReader).Decode(&metadata); err != nil {
   184→		return nil, nil, nil, fmt.Errorf("failed to decode metadata: %w", err)
   185→	}
   186→
   187→	// Read discussion (optional, may not exist yet)
   188→	var discussion Discussion
   189→	discussionEntry, err := tree.FindEntry(basePath + discussionFile)
   190→	if err == nil {
   191→		discussionBlob, blobErr := s.repo.BlobObject(discussionEntry.Hash)
   192→		if blobErr == nil {
   193→			discussionReader, readerErr := discussionBlob.Reader()
   194→			if readerErr == nil {
   195→				//nolint:errcheck,gosec // best-effort decode of optional discussion
   196→				json.NewDecoder(discussionReader).Decode(&discussion)
   197→				_ = discussionReader.Close()
   198→			}
   199→		}
   200→	}
   201→
   202→	// Read checkpoints (optional, may not exist yet)
   203→	var checkpoints Checkpoints
   204→	checkpointsEntry, err := tree.FindEntry(basePath + checkpointsFile)
   205→	if err == nil {
   206→		checkpointsBlob, blobErr := s.repo.BlobObject(checkpointsEntry.Hash)
   207→		if blobErr == nil {
   208→			checkpointsReader, readerErr := checkpointsBlob.Reader()
   209→			if readerErr == nil {
   210→				//nolint:errcheck,gosec // best-effort decode of optional checkpoints
   211→				json.NewDecoder(checkpointsReader).Decode(&checkpoints)
   212→				_ = checkpointsReader.Close()
   213→			}
   214→		}
   215→	}
   216→
   217→	return &metadata, &discussion, &checkpoints, nil
   218→}
