   236→// List returns all trail metadata from the entire/trails branch.
   237→func (s *Store) List() ([]*Metadata, error) {
   238→	tree, err := s.getBranchTree()
   239→	if err != nil {
   240→		// Branch doesn't exist yet — no trails
   241→		return nil, nil //nolint:nilerr // Expected when no trails exist yet
   242→	}
