   247→		return nil, fmt.Errorf("failed to flatten tree: %w", err)
   248→	}
   249→
   250→	// Find all metadata.json files
   251→	for path, entry := range entries {
   252→		if !strings.HasSuffix(path, "/"+metadataFile) {
   253→			continue
   254→		}
   255→
   256→		blob, err := s.repo.BlobObject(entry.Hash)
   257→		if err != nil {
   258→			continue
   259→		}
   260→		reader, err := blob.Reader()
   261→		if err != nil {
   262→			continue
   263→		}
