   406→// createCommit creates a commit on the trails branch.
   407→func (s *Store) createCommit(treeHash, parentHash plumbing.Hash, message, authorName, authorEmail string) (plumbing.Hash, error) {
   408→	now := time.Now()
   409→	sig := object.Signature{
   410→		Name:  authorName,
   411→		Email: authorEmail,
   412→		When:  now,
   413→	}
   414→
   415→	commit := &object.Commit{
   416→		TreeHash:  treeHash,
   417→		Author:    sig,
   418→		Committer: sig,
   419→		Message:   message,
   420→	}
   421→
   422→	if parentHash != plumbing.ZeroHash {
   423→		commit.ParentHashes = []plumbing.Hash{parentHash}
   424→	}
   425→
   426→	obj := s.repo.Storer.NewEncodedObject()
   427→	if err := commit.Encode(obj); err != nil {
   428→		return plumbing.ZeroHash, fmt.Errorf("failed to encode commit: %w", err)
   429→	}
   430→
   431→	hash, err := s.repo.Storer.SetEncodedObject(obj)
   432→	if err != nil {
   433→		return plumbing.ZeroHash, fmt.Errorf("failed to store commit: %w", err)
   434→	}
   435→
   436→	return hash, nil
   437→}
